<template><view class="page"><view class="card"><text class="title">提现申请</text><input v-model="form.amount" type="digit" placeholder="提现金额"/><input v-model="form.bankName" placeholder="开户银行"/><input v-model="form.bankAccount" placeholder="银行卡号"/><input v-model="form.accountName" placeholder="开户人姓名"/><text class="muted">手续费、最小提现金额以后端配置为准。</text><button class="primary" @click="submit">提交申请</button></view></view></template><script setup lang="ts">import { ref } from 'vue';import { assetApi } from '@/services/asset';const form=ref({amount:'',bankName:'',bankAccount:'',accountName:''});async function submit(){if(!form.value.amount||!form.value.bankName||!form.value.bankAccount||!form.value.accountName){uni.showToast({title:'请填写完整提现信息',icon:'none'});return}await assetApi.withdraw(form.value);uni.showToast({title:'申请已提交',icon:'success'});setTimeout(()=>uni.navigateBack(),400)}</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.title{font-size:34rpx;font-weight:900}input{height:82rpx;background:#f8f4ed;border-radius:12rpx;padding:0 20rpx;margin-top:20rpx}.muted{display:block;color:#8d8175;font-size:24rpx;margin-top:18rpx}button{margin-top:28rpx;height:84rpx;line-height:84rpx;width:100%;border:0;border-radius:999rpx}.primary{background:#b97700;color:#fff}button:after{border:0}</style>
